{"content": """"
DeBank Client — portfolio tracking, DeFi positions, and wallet analytics.
Docs: https://open.debank.com/
"""

import os
import time
import logging
from typing import Optional, List, Dict, Any

import requests

logger = logging.getLogger(__name__)

DEBANK_API_KEY = os.getenv("DEBANK_API_KEY", "")
DEBANK_BASE_URL = "https://api.debank.com"


class DeBankClient:
    """
    Query DeBank for wallet portfolios and DeFi positions.

    Usage:
        client = DeBankClient()
        portfolio = client.get_portfolio("vitalik.eth")
        positions = client.get_defi_positions("0x...")
        gas = client.get_gas_tracker()
    """

    def __init__(self, api_key: Optional[str] = None, cache_ttl: int = 120):
        self.api_key = api_key or DEBANK_API_KEY
        self.cache_ttl = cache_ttl
        self._cache: Dict[str, tuple[float, Any]] = {}

    # ─── Core endpoints ───────────────────────────────────────────────────

    def get_portfolio(self, address_or_ens: str) -> Dict[str, Any]:
        """
        Fetch full portfolio for an address or ENS name.

        Returns normalized dict with:
          - total_net_usd: float
          - assets: list of token holdings
          - debt_total_usd: float
          - position_list: DeFi positions
        """
        cache_key = f"debank_portfolio:{address_or_ens}"
        if self._is_cached(cache_key):
            return self._get_cached(cache_key)

        # Resolve ENS if needed
        address = self._resolve_ens(address_or_ens)

        headers = self._headers()
        if not headers:
            logger.error("DeBank API key required")
            return {}

        try:
            resp = requests.get(
                f"{DEBANK_BASE_URL}/portfolio",
                params={"address": address},
                headers=headers,
                timeout=15,
            )
            if resp.status_code == 403:
                logger.error("DeBank API key invalid or expired")
                return {}
            resp.raise_for_status()
            raw = resp.json()

            portfolio = self._normalize_portfolio(raw)
            self._set_cache(cache_key, portfolio)
            return portfolio

        except requests.RequestException as e:
            logger.error(f"DeBank portfolio fetch failed: {e}")
            return {}

    def get_defi_positions(self, address: str) -> List[Dict[str, Any]]:
        """
        Get DeFi protocol positions (lending, LP, staking, etc.).

        Returns list of positions, each with:
          - protocol_name, protocol_logo
          - position_type (lend/borrow/lp/stake)
          - supplied_usd, borrowed_usd
          - health_rate
        """
        cache_key = f"debank_positions:{address}"
        if self._is_cached(cache_key):
            return self._get_cached(cache_key)

        headers = self._headers()
        if not headers:
            return []

        try:
            resp = requests.get(
                f"{DEBANK_BASE_URL}/position_list",
                params={"address": address},
                headers=headers,
                timeout=15,
            )
            resp.raise_for_status()
            raw = resp.json()
            positions = self._normalize_positions(raw.get("data", []))
            self._set_cache(cache_key, positions)
            return positions

        except requests.RequestException as e:
            logger.error(f"DeBank positions fetch failed: {e}")
            return []

    def get_token_balances(self, address: str) -> List[Dict[str, Any]]:
        """Get all ERC20 token balances for an address."""
        cache_key = f"debank_tokens:{address}"
        if self._is_cached(cache_key):
            return self._get_cached(cache_key)

        headers = self._headers()
        if not headers:
            return []

        try:
            resp = requests.get(
                f"{DEBANK_BASE_URL}/token_list",
                params={"address": address},
                headers=headers,
                timeout=15,
            )
            resp.raise_for_status()
            raw = resp.json()
            tokens = raw.get("data", [])
            normalized = [self._normalize_token(t) for t in tokens]
            self._set_cache(cache_key, normalized)
            return normalized

        except requests.RequestException as e:
            logger.error(f"DeBank token list fetch failed: {e}")
            return []

    def get_gas_tracker(self) -> Dict[str, Any]:
        """
        Get current gas recommendations (safe/fast/instant).
        No auth required for this endpoint.
        """
        cache_key = "debank_gas"
        if self._is_cached(cache_key):
            return self._get_cached(cache_key)

        try:
            resp = requests.get(
                f"{DEBANK_BASE_URL}/gas_positions",
                timeout=10,
            )
            resp.raise_for_status()
            data = resp.json()
            self._set_cache(cache_key, data)
            return data
        except requests.RequestException as e:
            logger.error(f"DeBank gas tracker failed: {e}")
            return {}

    def get_wallet_risk(self, address: str) -> Dict[str, Any]:
        """
        Get wallet risk assessment from DeBank:
        -操守 social simulation status
        - Financial破产 analysis
        """
        cache_key = f"debank_risk:{address}"
        if self._is_cached(cache_key):
            return self._get_cached(cache_key)

        headers = self._headers()
        if not headers:
            return {}

        try:
            resp = requests.get(
                f"{DEBANK_BASE_URL}/risk_prediction",
                params={"address": address},
                headers=headers,
                timeout=15,
            )
            resp.raise_for_status()
            data = resp.json()
            self._set_cache(cache_key, data)
            return data
        except requests.RequestException as e:
            logger.error(f"DeBank risk prediction failed: {e}")
            return {}

    def get_social_simulation(self, address: str) -> Dict[str, Any]:
        """Get DeBank social simulation / identity data."""
        cache_key = f"debank_social:{address}"
        if self._is_cached(cache_key):
            return self._get_cached(cache_key)

        headers = self._headers()
        if not headers:
            return {}

        try:
            resp = requests.get(
                f"{DEBANK_BASE_URL}/social_simulation",
                params={"address": address},
                headers=headers,
                timeout=15,
            )
            resp.raise_for_status()
            data = resp.json()
            self._set_cache(cache_key, data)
            return data
        except requests.RequestException as e:
            logger.error(f"DeBank social simulation failed: {e}")
            return {}

    # ─── Normalizers ─────────────────────────────────────────────────────

    def _normalize_portfolio(self, raw: Dict) -> Dict[str, Any]:
        """Normalize DeBank portfolio response."""
        return {
            "total_net_usd": raw.get("total_net_usd", 0.0),
            "total_asset_usd": raw.get("total_asset_usd", 0.0),
            "debt_total_usd": raw.get("debt_total_usd", 0.0),
            "assets": raw.get("asset_list", []),
            "position_list": raw.get("position_list", []),
        }

    def _normalize_positions(self, positions: List[Dict]) -> List[Dict[str, Any]]:
        normalized = []
        for p in positions:
            normalized.append({
                "protocol_name": p.get("protocol_name", ""),
                "protocol_id": p.get("protocol_id", ""),
                "position_type": p.get("position_type", ""),
                "supplied_usd": p.get("supplied_usd", 0.0),
                "borrowed_usd": p.get("borrowed_usd", 0.0),
                "health_rate": p.get("health_rate"),
                "chain": p.get("chain", "eth"),
            })
        return normalized

    def _normalize_token(self, token: Dict) -> Dict[str, Any]:
        return {
            "symbol": token.get("symbol", ""),
            "address": token.get("contract_address", ""),
            "balance": token.get("balance", 0),
            "decimals": token.get("decimals", 18),
            "price_usd": token.get("price", 0.0),
            "value_usd": token.get("balance_usd", 0.0),
        }

    # ─── Helpers ─────────────────────────────────────────────────────────

    def _headers(self) -> Dict[str, str]:
        if not self.api_key:
            logger.warning("DeBank API key not set — set DEBANK_API_KEY env var")
            return {}
        return {
            "AccessKey": self.api_key,
            "Content-Type": "application/json",
        }

    def _resolve_ens(self, address_or_ens: str) -> str:
        """Pass through if already 0x address, otherwise return as-is (no ENS resolution here)."""
        if address_or_ens.startswith("0x"):
            return address_or_ens
        # DeBank API accepts ENS names directly
        return address_or_ens

    # ─── Cache ───────────────────────────────────────────────────────────

    def _is_cached(self, key: str) -> bool:
        if key in self._cache:
            ts, _ = self._cache[key]
            return (time.time() - ts) < self.cache_ttl
        return False

    def _get_cached(self, key: str) -> Any:
        return self._cache[key][1]

    def _set_cache(self, key: str, val: Any) -> None:
        self._cache[key] = (time.time(), val)
        if len(self._cache) > 300:
            oldest = min(self._cache, key=lambda k: self._cache[k][0])
            del self._cache[oldest]

    def clear_cache(self) -> None:
        self._cache.clear()
